                            yield r
                        buffer_rows, buffer_indices = [], []
                for r in yield_from_buffer():
                    yield r

        elif self._format == 'jsonl':
            with open(path, 'r', encoding='utf-8') as f:
                for idx, line in enumerate(f):
                    line = line.strip()
                    if not line:
                        continue
                    if idx in processed_indices:
