                    buffer_rows.append(json.loads(line))
                    buffer_indices.append(idx)
                    if len(buffer_rows) >= self.buffer:
                        for r, _ in [process_buffer()]:
                            yield r
                        buffer_rows, buffer_indices = [], []
                for r in yield_from_buffer():
