                bufferIndices.push(idx);
                if (bufferRows.length >= buffer) {{
                    yield* yieldFromBuffer();
                }}
            }}
            yield* yieldFromBuffer();
        }}

        if (this.cacheDir) {{
            this._saveToCache(filePath, processedIndices);
        }}
    }}
}}

function createPreprocessor(options) {{
    return new DynamicPreprocessor(options);
}}

module.exports = {{
