    }}

    fn save_to_cache(&self) {{
        if let Some(cache_dir) = &self.cache_dir {{
            if let Some(path) = &self.file_path {{
                let cache_path = format!("{{}}/{{}}_index.txt", cache_dir, md5::compute(path));
