void DynamicPreprocessor::open(const std::string& path)
{{
    if (file_stream_.is_open()) {{
        file_stream_.close();
    }}

    file_stream_.open(path);
    if (!file_stream_.is_open()) {{
        throw std::runtime_error("Cannot open file: " + path);
    }}

    current_row_ = 0;
    reset_state();

    if (!cache_dir_.empty()) {{
